class Solution {
public:
    int longestSubsequence(string s, int k) {
        int countZeroes = 0;
        for (char c : s) {
            if (c == '0') countZeroes++;
        }
        long long binaryNum = 0;
        int countOnes = 0;
        for (int i = s.size() - 1; i >= 0; --i) {
            if (s[i] == '1') {
                binaryNum += (1LL << countOnes);
                if (binaryNum > k) break;
                countOnes++;
            }
        }
        return countOnes + countZeroes;
    }
};
```
